prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?taskMerkitse ?taskLasku ?seqAfter WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "6e8e145a4f51488c81c0c89e863a27fa" .
  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?taskMerkitse a bboExt:ChoreographyTask ;
                 tai:belongsTo ?choreo ;
                 bbo:name ?nameMerkitse .
  FILTER(LCASE(STR(?nameMerkitse)) = LCASE("Merkitse varaus"))

  ?taskLasku a bboExt:ChoreographyTask ;
            tai:belongsTo ?choreo ;
            bbo:name ?nameLasku .
  FILTER(LCASE(STR(?nameLasku)) = LCASE("Lasku"))

  # any immediate next node(s) from Merkitse varaus
  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?taskMerkitse ;
        bbo:has_targetRef ?taskLasku .
  BIND("immediate" AS ?seqAfter)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelId ?origId ?normId ?modelName ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:originalId ?origId ;
         tai:normalizedId ?normId ;
         bbo:name ?modelName .
  FILTER(?normId = "6e8e145a4f51488c81c0c89e863a27fa" || ?origId = "6e8e145a4f51488c81c0c89e863a27fa")

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?merkitse ?merkitseName ?next ?nextName ?nextType WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "6e8e145a4f51488c81c0c89e863a27fa" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?merkitse a bboExt:ChoreographyTask ;
           tai:belongsTo ?choreo ;
           bbo:name ?merkitseName .
  FILTER(CONTAINS(LCASE(STR(?merkitseName)), "merkitse varaus"))

  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?merkitse ;
        bbo:has_targetRef ?next .

  OPTIONAL { ?next bbo:name ?nextName . }
  OPTIONAL { ?next a ?nextType . }

  FILTER(CONTAINS(LCASE(STR(?nextName)), "lasku") ||
          CONTAINS(LCASE(STR(?nextName)), "merkitse") ||
          1=1)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?next ?nextName ?viaType WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "6e8e145a4f51488c81c0c89e863a27fa" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?start a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?startName .
  FILTER(CONTAINS(LCASE(STR(?startName)), "merkitse varaus"))

  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?next .
  OPTIONAL { ?next bbo:name ?nextName . }
  OPTIONAL { ?next a ?viaType . }

  FILTER(bound(?nextName))
  FILTER(CONTAINS(LCASE(STR(?nextName)), "lasku") ||
          CONTAINS(LCASE(STR(?nextName)), "merkitse varaus"))
}
ORDER BY ?nextName
LIMIT 25

